mapper.select:
select fi.*
from scheduler_flow_instance fi



            and (fi.flow_name like concat('%', #{query.flowKeyword}, '%')
                or fi.id::text = #{query.flowKeyword}
                or fi.flow_id::text = #{query.flowKeyword})


            and exists (
                select 1
                from scheduler_task_instance ti
                where ti.flow_instance_id = fi.id
                  and (ti.task_name like concat('%', #{query.taskKeyword}, '%')
                    or ti.id::text = #{query.taskKeyword}
                    or ti.task_id::text = #{query.taskKeyword})
            )


            and fi.status = #{query.status}


            and fi.schedule_time >= #{query.scheduleStartTime}


            and fi.schedule_time <= #{query.scheduleEndTime}


            and fi.start_time >= #{query.startTime}


            and fi.start_time <= #{query.endTime}


            and fi.end_time >= #{query.finishStartTime}


            and fi.end_time <= #{query.finishEndTime}



order by fi.schedule_time desc nulls last, fi.create_time desc

select * from scheduler_flow_instance where status not in ('31', '33')
and flow_id = #{flowId}
order by schedule_time desc

select *
from scheduler_flow_instance
where flow_id = #{flowId}

    and publish_version = #{version}

order by schedule_time desc
limit 1

select *
from scheduler_flow_instance
where status in

    #{status}

order by update_time asc
limit #{limit}

mapper.delete:
delete from scheduler_flow_instance
where id in

    #{instanceId}
